viewof wedge_controls = Inputs.form({
  tau:   Inputs.range([0, 60],   {value: 35,  step: 1,    label: "Porezni klin τ (%):"}),
  eps_L: Inputs.range([0.1, 1.5], {value: 0.4, step: 0.05, label: "Elastičnost ponude rada εL:"})
})









Prikaži kod
tau = wedge_controls.tau









Prikaži kod
eps_L = wedge_controls.eps_L









Prikaži kod
{
  // Labour market: equilibrium fixed at (L*, W*) = (50, 50).
  // Demand for labour: W = a - b·L, calibrated so |εD| = 1 at equilibrium → b = 1.
  // Supply of labour: W = c + d·L, with εL controlling slope: d = 1 / εL.
  const Lstar = 50;
  const Wstar = 50;
  const Lmax = 110;
  const Wmax = 110;

  const b = 1;                       // demand slope (fixed reference elasticity)
  const a = Wstar + b * Lstar;       // demand intercept
  const d_slope = 1 / eps_L;         // supply slope from labour-supply elasticity
  const c = Wstar - d_slope * Lstar; // supply intercept

  // Tax wedge as percent of gross wage. Wedge t (in absolute money) shifts supply up.
  // Solve for new equilibrium with wedge t such that t = τ · Wbruto.
  // Post-tax: a - b·L = c + t + d·L  with  t = τ · Wbruto = τ · (a - b·L)
  // ⇒ a - b·L = c + τ·(a - b·L) + d·L
  // ⇒ (a - b·L)·(1 - τ) = c + d·L
  // ⇒ a·(1 - τ) - b·(1 - τ)·L = c + d·L
  // ⇒ L_t = [a·(1 - τ) - c] / [b·(1 - τ) + d]
  const tauFrac = tau / 100;
  const Lt = Math.max(0, (a * (1 - tauFrac) - c) / (b * (1 - tauFrac) + d_slope));
  const Wbruto = a - b * Lt;
  const Wneto  = Wbruto * (1 - tauFrac);
  const wedgeAbs = Wbruto - Wneto;

  // Revenue and DWL
  const dL = Lstar - Lt;
  const revenue = wedgeAbs * Lt;
  const dwl     = 0.5 * wedgeAbs * dL;

  const Ls = d3.range(0, Lmax + 1);
  const demand    = Ls.map(l =&gt; ({L: l, W: a - b * l})).filter(p =&gt; p.W &gt;= 0 && p.W &lt;= Wmax);
  const supply    = Ls.map(l =&gt; ({L: l, W: c + d_slope * l})).filter(p =&gt; p.W &gt;= 0 && p.W &lt;= Wmax);
  const supplyTax = Ls.map(l =&gt; ({L: l, W: c + wedgeAbs + d_slope * l})).filter(p =&gt; p.W &gt;= 0 && p.W &lt;= Wmax);

  // Wedge revenue rectangle
  const wedgeRect = [
    {L: 0,  W: Wneto},
    {L: Lt, W: Wneto},
    {L: Lt, W: Wbruto},
    {L: 0,  W: Wbruto}
  ];

  return Plot.plot({
    width: 760,
    height: 500,
    marginLeft: 60,
    marginBottom: 55,
    style: {fontSize: "12px", fontFamily: "Public Sans, system-ui, sans-serif", color: "#3A332D"},
    x: {label: "Rad (L) →", domain: [0, Lmax], grid: false},
    y: {label: "↑ Nadnica (W)", domain: [0, Wmax], grid: true},
    marks: [
      Plot.ruleY([0], {stroke: "#C9C3B8"}),

      // Wedge rectangle (tax revenue collected from labour)
      Plot.line([...wedgeRect, wedgeRect[0]],
        {x: "L", y: "W", stroke: "#3A332D", strokeWidth: 1,
         fill: "#E0D8C8", fillOpacity: 0.6, curve: "linear"}),

      // Curves
      Plot.line(demand,    {x: "L", y: "W", stroke: "#2D5A8E", strokeWidth: 2.5}),
      Plot.line(supply,    {x: "L", y: "W", stroke: "#4A6B5C", strokeWidth: 2}),
      Plot.line(supplyTax, {x: "L", y: "W", stroke: "#4A6B5C", strokeWidth: 2, strokeDasharray: "6,4"}),

      // Wage guides
      Plot.ruleY([Wbruto], {stroke: "#6B6357", strokeDasharray: "2,2"}),
      Plot.ruleY([Wneto],  {stroke: "#6B6357", strokeDasharray: "2,2"}),

      // Vertical wedge line
      Plot.ruleX([Lt], {y1: Wneto, y2: Wbruto, stroke: "#6B1F26", strokeWidth: 3}),

      // Equilibrium dots
      Plot.dot([{L: Lstar, W: Wstar}], {x: "L", y: "W", r: 5, fill: "#3A332D", stroke: "white", strokeWidth: 2}),
      Plot.dot([{L: Lt, W: Wbruto}, {L: Lt, W: Wneto}],
        {x: "L", y: "W", r: 4, fill: "#6B1F26", stroke: "white", strokeWidth: 1.5}),

      // Curve labels
      Plot.text([{x: Lmax * 0.85, y: a - b * Lmax * 0.85, label: "Potražnja za radom (D)"}],
        {x: "x", y: "y", text: "label", fill: "#2D5A8E", fontSize: 12, fontWeight: 600, dy: -8}),
      Plot.text([{x: Lmax * 0.85, y: c + d_slope * Lmax * 0.85, label: `Ponuda rada (εL=${eps_L.toFixed(2)})`}],
        {x: "x", y: "y", text: "label", fill: "#4A6B5C", fontSize: 12, fontWeight: 600, dy: -8}),
      Plot.text([{x: Lmax * 0.85, y: c + wedgeAbs + d_slope * Lmax * 0.85, label: "Ponuda + klin"}],
        {x: "x", y: "y", text: "label", fill: "#4A6B5C", fontSize: 12, fontWeight: 600, dy: -8}),

      // Wage labels
      Plot.text([{x: 2, y: Wbruto, label: `Bruto nadnica = ${Wbruto.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start", dy: -8, fontSize: 12, fill: "#1C1916", fontWeight: 600}),
      Plot.text([{x: 2, y: Wneto, label: `Neto nadnica = ${Wneto.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start", dy: 14, fontSize: 12, fill: "#1C1916", fontWeight: 600}),
      Plot.text([{x: Lt, y: (Wbruto + Wneto) / 2, label: `Klin = ${wedgeAbs.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start", dx: 8,
         fontSize: 13, fill: "#6B1F26", fontWeight: 700}),

      // Top readouts
      Plot.text([{x: 2, y: Wmax * 0.97,
         label: `Porezni prihod: ${revenue.toFixed(1)}   |   Mrtvi teret: ${dwl.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 13, fill: "#3A332D", fontWeight: 700}),
      Plot.text([{x: 2, y: Wmax * 0.91,
         label: `Pad zaposlenosti: ΔL = ${dL.toFixed(1)}  (${(dL / Lstar * 100).toFixed(1)}%)`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 12, fill: "#3A332D", fontWeight: 500})
    ]
  });
}







Kako čitati graf. Plava krivulja je potražnja poslodavaca za radom, zelena puna ponuda rada (radnici), zelena isprekidana ponuda nakon poreznog klina — udarnik svih davanja koja terete plaću (porez na dohodak, prirez, doprinosi zaposlenika i poslodavca). Crveni okomiti odsječak je veličina klina. Bruto nadnica je trošak rada za poslodavca; neto nadnica je dohodak koji radnik odnosi kući. Ljubičasti pravokutnik prikazuje ukupni porezni prihod države (klin × broj zaposlenih).
Što isprobati. (1) Pri niskoj elastičnosti ponude rada (εL ≈ 0,15, npr. radnici s niskim alternativama) i klinu od 35 %: pad zaposlenosti je malen, prihod države velik. To je razlog zašto su porezi na rad fiskalno izdašni i u zemljama s visokim opterećenjem rada. (2) Povećajte εL na ~1,0 (npr. mladi, žene s djecom, radnici blizu mirovine — skupine s više fleksibilnosti): isti klin sada uzrokuje znatno veći pad zaposlenosti i veći mrtvi teret. Upravo zato moderna teorija optimalnog oporezivanja preporučuje niže efektivne stope na rad za skupine s elastičnijom ponudom rada. (3) Pri εL = 0,4, povucite klin s 20 % na 50 %: prihod isprva raste, ali pri vrlo visokim klinovima može se i smanjivati — radnici reagiraju smanjenjem ponude rada (najavak Lafferove logike za tržište rada). Ovaj graf konkretizira zašto je za Hrvatsku, koja ima među višim klinovima u EU, pitanje strukture poreznog opterećenja rada ključno za zaposlenost i konkurentnost (Šimović 2022.).
U ekonomskom smislu, porezni klin djeluje kao distorzija tržišta rada. Poslodavci donose odluke na temelju bruto troška rada, dok radnici reagiraju na neto plaću. Kada se uvedu porezi, bruto trošak raste, a neto plaća pada, što dovodi do smanjenja zaposlenosti i količine rada u odnosu na razinu bez oporezivanja. Time porezni klin izravno generira mrtvi teret poreza (Gruber 2019.; Stiglitz 2015.).

Teorija optimalnog oporezivanja
Teorija optimalnog oporezivanja razvijena je kako bi odgovorila na temeljno pitanje javnih financija: kako dizajnirati porezni sustav koji maksimizira društveno blagostanje uz minimalne distorzije u gospodarstvu (Stiglitz 2015.; Gruber 2019.). Za razliku od ranijih normativnih pristupa, ova teorija koristi formalne modele kako bi analizirala ponašanje pojedinaca i ograničenja s kojima se država suočava. U središtu cijelog pristupa nalazi se ključni problem: svaki porez istovremeno redistribuira dohodak i narušava ekonomske poticaje. Upravo zato optimalno oporezivanje nije pitanje „koliko oporezivati”, već kako rasporediti porezno opterećenje tako da gubitak blagostanja bude što manji, uz ostvarenje društvenih ciljeva.

Definicija 16.1 Mrtvi teret poreza je gubitak ukupnog blagostanja koji nastaje zato što porez mijenja relativne cijene i odvraća sudionike od razmjena koje bi inače bile uzajamno korisne. Formalno, ako je \(Q^*\) ravnotežna količina prije oporezivanja, a \(Q_t\) količina nakon uvođenja poreza po jedinici \(t\), mrtvi teret je \(DWL \approx \tfrac{1}{2}\,t\,(Q^* - Q_t)\). On raste s kvadratom porezne stope i s elastičnošću ponude i potražnje.


Propozicija 16.1 Ramseyevo pravilo. Pri zadanom prihodu koji država treba prikupiti, mrtvi teret oporezivanja minimizira se kada se porezne stope na različita dobra postave tako da postotno smanjenje potraživane količine bude jednako za sva dobra. Posljedica: dobra s relativno neelastičnom potražnjom trebaju biti relativno više oporezivana — jer manje reagiraju na promjenu cijene, pa generiraju manji mrtvi teret po jedinici prihoda (Ramsey 1927.).

Ramsey, Frank P. 1927. „A Contribution to the Theory of Taxation“. Economic Journal 37 (145): 47–61. https://doi.org/10.2307/2222721.

Početak moderne teorije optimalnog oporezivanja vezuje se uz rad Franka Ramseya, koji je prvi formalno postavio pitanje: kako rasporediti poreze na različita dobra kako bi se minimizirao mrtvi teret uz zadane porezne prihode. Ramsey je pokazao da optimalno oporezivanje ne znači jednako oporezivanje svih dobara. Naprotiv, njegov ključni rezultat glasi: dobra s neelastičnom potražnjom trebaju biti relativno više oporezovana. Intuicija iza ovog rezultata proizlazi iz koncepta mrtvog tereta. Kada porez povećava cijenu nekog dobra, potrošači smanjuju potražnju. Ako je ta reakcija velika (elastična potražnja), dolazi do značajnog pada količine i velikog gubitka blagostanja. Ako je reakcija mala (neelastična potražnja), porez ima manji učinak na količinu i time manji mrtvi teret. Ovaj rezultat ima jasne praktične implikacije — upravo zato se u stvarnim poreznim sustavima često primjenjuju visoke trošarine na proizvode poput goriva ili duhana, čija je potražnja relativno neelastična.


