Prikaži kod
{
  // Two-period model. Endowment Y in period 1, no income in period 2.
  // Without tax: C2 = (1+r)·(Y − C1).        Optimum chooses C1, C2 to maximise CRRA utility.
  // With tax τ on the return: C2 = (1+r·(1−τ))·(Y − C1).
  // CRRA utility: U = u(C1) + β·u(C2),  with β = 1/(1+ρ),  ρ = 0.04 (subjective discount).
  // Closed-form for CRRA: C2/C1 = [β·(1+r_net)]^σ.
  const Y = 100;
  const Cmax = 130;
  const beta = 1 / 1.04;

  const tauFrac = tau_k / 100;
  const r0 = r;
  const r1 = r * (1 - tauFrac);

  // Optimum given net return r_net and elasticity σ:
  // C2 / C1 = [β·(1 + r_net)]^σ.   Budget: C2 = (1 + r_net)·(Y − C1).
  // ⇒ C1 = Y / (1 + (1 + r_net) / k),  where k = [β·(1 + r_net)]^σ.
  function optimum(r_net) {
    const k = Math.pow(beta * (1 + r_net), sigma);
    const C1 = Y / (1 + (1 + r_net) / k);
    const C2 = (1 + r_net) * (Y - C1);
    return {C1, C2, k};
  }

  const before = optimum(r0);
  const after  = optimum(r1);

  // Budget lines as two-point segments
  const budgetNoTax = [
    {C1: 0, C2: (1 + r0) * Y},
    {C1: Y, C2: 0}
  ];
  const budgetTax = [
    {C1: 0, C2: (1 + r1) * Y},
    {C1: Y, C2: 0}
  ];

  // Indifference curves through the two optima.
  // For CRRA: u(C) = C^(1-1/σ)/(1-1/σ)  (or ln(C) if σ=1).
  // The indifference curve through (C1*, C2*) is the locus where u(C1)+β·u(C2) = constant.
  function indiff(C1opt, C2opt) {
    const eps = 1e-9;
    const uOf = c =&gt; {
      if (Math.abs(sigma - 1) &lt; 1e-6) return Math.log(Math.max(c, eps));
      const e = 1 - 1 / sigma;
      return Math.pow(Math.max(c, eps), e) / e;
    };
    const Ubar = uOf(C1opt) + beta * uOf(C2opt);
    const pts = [];
    const C1grid = d3.range(2, Cmax + 1, 1);
    for (const C1 of C1grid) {
      // Solve uOf(C1) + β·uOf(C2) = Ubar  →  uOf(C2) = (Ubar - uOf(C1))/β
      const target = (Ubar - uOf(C1)) / beta;
      let C2;
      if (Math.abs(sigma - 1) &lt; 1e-6) {
        C2 = Math.exp(target);
      } else {
        const e = 1 - 1 / sigma;
        const arg = target * e;
        if (arg &lt;= 0) continue;
        C2 = Math.pow(arg, 1 / e);
      }
      if (isFinite(C2) && C2 &gt; 0 && C2 &lt; Cmax * 1.5) pts.push({C1, C2});
    }
    return pts;
  }

  const indiffBefore = indiff(before.C1, before.C2);
  const indiffAfter  = indiff(after.C1,  after.C2);

  // Welfare change as a percentage of "before" utility (qualitative readout)
  const dC1 = after.C1 - before.C1;
  const dC2 = after.C2 - before.C2;

  return Plot.plot({
    width: 760,
    height: 520,
    marginLeft: 65,
    marginBottom: 55,
    style: {fontSize: "12px", fontFamily: "Public Sans, system-ui, sans-serif", color: "#3A332D"},
    x: {label: "Sadašnja potrošnja C₁ →", domain: [0, Cmax], grid: false},
    y: {label: "↑ Buduća potrošnja C₂",   domain: [0, Cmax], grid: true},
    marks: [
      Plot.ruleY([0], {stroke: "#C9C3B8"}),

      // Budget line — no tax
      Plot.line(budgetNoTax, {x: "C1", y: "C2", stroke: "#4A6B5C", strokeWidth: 2.5}),
      // Budget line — with tax
      Plot.line(budgetTax,   {x: "C1", y: "C2", stroke: "#4A6B5C", strokeWidth: 2, strokeDasharray: "6,4"}),

      // Indifference curves
      Plot.line(indiffBefore, {x: "C1", y: "C2", stroke: "#2D5A8E", strokeWidth: 2}),
      Plot.line(indiffAfter,  {x: "C1", y: "C2", stroke: "#6B1F26", strokeWidth: 2, strokeDasharray: "4,3"}),

      // Endowment point
      Plot.dot([{C1: Y, C2: 0}], {x: "C1", y: "C2", r: 4, fill: "#3A332D", stroke: "white", strokeWidth: 1.5}),

      // Optima
      Plot.dot([before], {x: "C1", y: "C2", r: 6, fill: "#2D5A8E", stroke: "white", strokeWidth: 2}),
      Plot.dot([after],  {x: "C1", y: "C2", r: 6, fill: "#6B1F26", stroke: "white", strokeWidth: 2}),

      // Drop-lines for both optima
      Plot.ruleX([before.C1], {y1: 0, y2: before.C2, stroke: "#CBD8D2", strokeDasharray: "2,2"}),
      Plot.ruleY([before.C2], {x1: 0, x2: before.C1, stroke: "#CBD8D2", strokeDasharray: "2,2"}),
      Plot.ruleX([after.C1],  {y1: 0, y2: after.C2,  stroke: "#E0C5C2", strokeDasharray: "2,2"}),
      Plot.ruleY([after.C2],  {x1: 0, x2: after.C1,  stroke: "#E0C5C2", strokeDasharray: "2,2"}),

      // Labels on optima
      Plot.text([{C1: before.C1, C2: before.C2, label: "Bez poreza"}],
        {x: "C1", y: "C2", text: "label", textAnchor: "start", dx: 8, dy: -10,
         fontSize: 12, fill: "#2D5A8E", fontWeight: 600}),
      Plot.text([{C1: after.C1, C2: after.C2, label: "S porezom"}],
        {x: "C1", y: "C2", text: "label", textAnchor: "start", dx: 8, dy: 14,
         fontSize: 12, fill: "#6B1F26", fontWeight: 600}),

      // Endowment label
      Plot.text([{C1: Y, C2: 0, label: `Y = ${Y}`}],
        {x: "C1", y: "C2", text: "label", textAnchor: "start", dx: 6, dy: -8,
         fontSize: 11, fill: "#3A332D"}),

      // Top readouts
      Plot.text([{x: 2, y: Cmax * 0.97,
         label: `Štednja s = Y − C₁:  ${(Y - before.C1).toFixed(1)}  →  ${(Y - after.C1).toFixed(1)}  (Δ = ${(dC1 &lt; 0 ? "+" : "−")}${Math.abs(dC1).toFixed(1)})`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 13, fill: "#3A332D", fontWeight: 700}),
      Plot.text([{x: 2, y: Cmax * 0.91,
         label: `Neto prinos: ${(r0 * 100).toFixed(1)} %  →  ${(r1 * 100).toFixed(2)} %    |    σ = ${sigma.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 12, fill: "#3A332D", fontWeight: 500})
    ]
  });
}







Kako čitati graf. Vodoravna os je sadašnja potrošnja C₁, okomita buduća potrošnja C₂. Zelena puna linija je proračunska linija bez poreza, zelena isprekidana s porezom na prinos — ona se zakreće oko točke darivanja Y jer porez smanjuje neto kamatnu stopu. Plava puna krivulja je krivulja indiferencije kroz početni optimum, crvena isprekidana kroz novi optimum. Plava točka je optimum bez poreza, crvena s porezom. U vrhu se ispisuje promjena štednje (s = Y − C₁).
Što isprobati. (1) Pri σ = 1,0 (logaritamska korisnost — supstitucijski i dohodovni učinak približno se poništavaju) i poreznoj stopi od 25 %: optimum se neznatno mijenja, odnosno štednja ostaje gotovo ista. (2) Povećajte σ na ~1,8 (potrošač spreman lako supstituirati potrošnju kroz vrijeme): povećanje poreza značajno smanjuje štednju — supstitucijski učinak nadjačava dohodovni. Ovo je teorijski temelj argumenata Atkinsona i Stiglitza protiv visokih poreza na kapital u sustavima s razvijenim porezom na dohodak. (3) Smanjite σ na ~0,3 (potrošač snažno preferira ravnomjernu potrošnju): porez smanjuje neto prinos, ali pojedinac pojačava štednju kako bi održao buduću razinu potrošnje — dohodovni učinak nadjačava. Praktična poruka. Smjer učinka oporezivanja kapitala na štednju nije jednoznačan; ovisi o elastičnosti intertemporalne supstitucije σ — empirijskom parametru koji teorija optimalnog oporezivanja (Atkinson i Stiglitz 1980.) pokušava izmjeriti, ali oko čije vrijednosti i danas ne postoji znanstveni konsenzus.
Atkinson–Stiglitz teorem (Atkinson i Stiglitz 1980.) — Atkinson i Stiglitz analizirali su pitanje treba li različite vrste potrošnje oporezivati različitim stopama. Njihov ključni rezultat glasi: ako je porez na dohodak optimalno dizajniran, tada diferencirano oporezivanje potrošnje nije potrebno. Drugim riječima, nema potrebe dodatno oporezivati određene proizvode višim ili nižim stopama ako se redistribucija već učinkovito provodi kroz porez na dohodak. Ovaj rezultat ima važne implikacije za dizajn sustava PDV-a. Teorijski, optimalan sustav bi imao jedinstvenu stopu PDV-a, bez izuzetaka. Međutim, u praksi gotovo sve zemlje koriste snižene stope za osnovna dobra, što pokazuje da politički i socijalni ciljevi često nadjačavaju teorijsku optimalnost.
Progresivno oporezivanje i teorija žrtve — progresivno oporezivanje podrazumijeva sustav u kojem prosječna porezna stopa raste s razinom dohotka. Temeljna ekonomska logika takvog sustava proizlazi iz ideje opadajuće granične korisnosti dohotka. Na toj osnovi razvijena je teorija žrtve, koja pokušava normativno opravdati raspodjelu poreznog tereta. Postoje tri varijante: jednaka apsolutna žrtva (svi porezni obveznici trebaju izgubiti isti iznos korisnosti), jednaka proporcionalna žrtva (svi gube isti udio ukupne korisnosti) i jednaka granična žrtva (marginalna žrtva treba biti jednaka za sve). Upravo posljednja varijanta vodi do zaključka da je optimalno progresivno oporezivanje, jer se redistribucijom dohotka izjednačavaju granične korisnosti među pojedincima (Musgrave i Musgrave 1989.). Međutim, suvremena teorija naglašava kompromis: iako progresivnost povećava pravednost, ona može stvoriti distorzije u ponašanju (npr. smanjiti radne poticaje), pa optimalna razina progresivnosti ovisi o ravnoteži između efikasnosti i jednakosti (Saez 2001.).

Saez, Emmanuel. 2001. „Using Elasticities to Derive Optimal Income Tax Rates“. Review of Economic Studies 68 (1): 205–29. https://doi.org/10.1111/1467-937X.00166.
Lafferova krivulja — iako nije dio formalne teorije optimalnog oporezivanja u užem smislu, Lafferova krivulja često se koristi kao intuitivni alat za razumijevanje odnosa između poreznih stopa i poreznih prihoda.


